solution:
def cloneGraph(node):
    if not node:
        return None
    clones = {}
    def dfs(n):
        if n in clones:
            return clones[n]
        clone = Node(n.val)
        clones[n] = clone
        clone.neighbors = [dfs(neighbor) for neighbor in n.neighbors]
        return clone
    return dfs(node)
